const sessionId = String(body.sessionId ?? 'default');
const userInput = String(body.userInput ?? '').trim();
const inputType = String(body.inputType ?? 'text');

if (!sessions[sessionId]) {
  sessions[sessionId] = {
    currentState: 0,
    productList: ['süt', 'yumurta'],
    currentItemIndex: 0,
    foundItems: [],
    missingItems: [],
    hintCount: 0,
    subState: 'INIT',
    timeoutCount: 0,
    notFoundAttempts: 0,
    notFoundItem: null,
    notFoundReason: null,
    exceptionChoice: null,
    previousState: null
  };
}

const session = JSON.parse(JSON.stringify(sessions[sessionId]));
return [{ json: { sessionId, userInput, inputType, session } }];

function normalize(str) {
  return str.toLowerCase()
    .replace(/ş/g, 's').replace(/ı/g, 'i').replace(/ö/g, 'o')
    .replace(/ü/g, 'u').replace(/ç/g, 'c').replace(/ğ/g, 'g')
    .replace(/[^a-z0-9\s]/g, '').trim();
}
function levenshtein(a, b) {
  const m = a.length, n = b.length;
  const dp = Array.from({ length: m + 1 }, (_, i) => [i]);
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++)
    for (let j = 1; j <= n; j++)
      dp[i][j] = a[i-1] === b[j-1] ? dp[i-1][j-1] : 1 + Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
  return dp[m][n];
}
function dynamicTolerance(word) {
  const len = word.length;
  if (len <= 3) return 0; if (len <= 5) return 1; if (len <= 8) return 2; return 3;
}
function substringScore(input, keyword) {
  if (input.includes(keyword)) return 1.0;
  const minLen = Math.floor(keyword.length * 0.6);
  for (let i = 0; i <= keyword.length - minLen; i++)
    if (input.includes(keyword.slice(i, i + minLen))) return 0.7;
  return 0;
}
function fuzzyMatch(input, keywords) {
  const normInput = normalize(input);
  const inputWords = normInput.split(/\s+/);
  for (const kw of keywords) {
    const normKw = normalize(kw);
    const kwWords = normKw.split(/\s+/);
