    const normKw = normalize(kw);
    const kwWords = normKw.split(/\s+/);
    if (normInput.includes(normKw)) return true;
    if (substringScore(normInput, normKw) >= 0.7) return true;
    let matched = 0;
    for (const kwWord of kwWords) {
      const tol = dynamicTolerance(kwWord);
      for (const inputWord of inputWords)
        if (levenshtein(inputWord, kwWord) <= tol) { matched++; break; }
    }
    if (matched / kwWords.length >= 0.7) return true;
  }
  return false;
}
function buildSystemPrompt(stateInfo) {
  return `Sen otizmli bireyler için alışveriş becerisi eğitimi veren, sabırlı ve destekleyici bir asistansın.\nGÖREV: Kullanıcının mesajını analiz et ve JSON formatında yanıt ver.\nMEVCUT DURUM:\n- State: ${stateInfo.currentState}\n- SubState: ${stateInfo.subState}\n- Senaryo: ${stateInfo.scenario}\nKURALLAR:\n- Yanıtın kısa (1-2 cümle), net, pozitif ve Türkçe olmalı\n- Kaygı yaratma, sade ve dostane ol\nYANIT FORMATI (sadece JSON, başka hiçbir şey yazma):\n{\n  "response": "kullanıcıya verilecek yanıt",\n  "nextState": 5,\n  "nextSubState": "${stateInfo.subState}"\n}`;
}

// ============================================================
// STATE 5 - KASAYA GEÇİŞ
// ============================================================
const sessions = $getWorkflowStaticData('global');
const raw = $input.first().json;
const sessionId = raw.sessionId;
const userInput = String(raw.userInput || '').trim();
const session = JSON.parse(JSON.stringify(raw.session));

let response = '';
let needsLLM = false;
let llmSystemPrompt = '';
let llmUserPrompt = '';

const isTimeout = userInput === '__timeout__';
const foundStr = (session.foundItems || []).join(', ') || 'yok';
const missingStr = (session.missingItems || []).join(', ') || 'yok';

if (isTimeout) {
  session.timeoutCount = (session.timeoutCount || 0) + 1;
} else {
  session.timeoutCount = 0;
}

switch (session.subState) {

  case 'INIT':
    response = `Listendeki ürünler: ${foundStr}\nEksikler: ${missingStr}\n\nKasaya geçelim mi?`;
    session.subState = 'CHECKOUT_DECISION';
    break;

  case 'CHECKOUT_DECISION':
    if (isTimeout) {
      response = `Kasaya geçelim mi?`;
      break;
    }
    if (fuzzyMatch(userInput, ['evet', 'kasaya', 'gecelim', 'tamam', 'ok', 'hadi'])) {
      response = `Kasada beklerken ne yapmak istersin?\n1️⃣ Telefon notlarına bak\n2️⃣ Nefes egzersizi yap\n3️⃣ Kasiyere selam ver`;
      session.subState = 'QUEUE_ACTIVITY';
    } else {
      needsLLM = true;
      llmSystemPrompt = buildSystemPrompt({
        currentState: 5, subState: 'CHECKOUT_DECISION',
        scenario: 'Kullanıcı kasaya geçmek istiyor mu? Evet ise nextSubState: QUEUE_ACTIVITY yap. Belirsizse kasaya geçmek isteyip istemediğini sor.'
      });
      llmUserPrompt = userInput;
    }
    break;

  case 'QUEUE_ACTIVITY':
    if (isTimeout) {
      response = `Kasada beklerken ne yapmak istersin?\n1️⃣ Telefon notlarına bak\n2️⃣ Nefes egzersizi yap\n3️⃣ Kasiyere selam ver`;
      break;
    }
    if (fuzzyMatch(userInput, ['1', 'telefon', 'not', 'notlar'])) {
      needsLLM = true;
      llmSystemPrompt = buildSystemPrompt({
        currentState: 5, subState: 'PAYMENT',
        scenario: 'Kullanıcı kasada beklerken telefon notlarına bakıyor. Bunu olumlu karşıla, kısa yorum yap. nextSubState: PAYMENT yap.'
      });
      llmUserPrompt = '1';
      session.subState = 'PAYMENT';
    } else if (fuzzyMatch(userInput, ['2', 'nefes', 'egzersiz', 'nefes al'])) {
      needsLLM = true;
      llmSystemPrompt = buildSystemPrompt({
        currentState: 5, subState: 'PAYMENT',
        scenario: 'Kullanıcı kasada nefes egzersizi yapacak. 4-7-8 nefes tekniğini basitçe anlat: 4 say nefes al, 7 say tut, 8 say ver. nextSubState: PAYMENT yap.'
      });
      llmUserPrompt = '2';
      session.subState = 'PAYMENT';
    } else if (fuzzyMatch(userInput, ['3', 'kasiyer', 'selam', 'merhaba'])) {
      needsLLM = true;
      llmSystemPrompt = buildSystemPrompt({
        currentState: 5, subState: 'PAYMENT',
        scenario: 'Kullanıcı kasiyere selam verecek. "Merhaba" veya "İyi günler" demesini teşvik et. Cesaret ver. nextSubState: PAYMENT yap.'
      });
      llmUserPrompt = '3';
      session.subState = 'PAYMENT';
    } else {
      needsLLM = true;
      llmSystemPrompt = buildSystemPrompt({
        currentState: 5, subState: 'QUEUE_ACTIVITY',
        scenario: 'Kullanıcı kasada beklerken 3 seçenekten birini seçmeli: 1=Telefon notları, 2=Nefes egzersizi, 3=Kasiyere selam. Mesajdan seçimi anla. Anlaşılamazsa tekrar listele. nextSubState: PAYMENT yap.'
      });
      llmUserPrompt = userInput;
    }
    break;

  case 'PAYMENT':
    if (isTimeout) {
      response = `Ödeme yapmak için aşağıdaki butonu kullanabilirsin. 💳`;
      break;
    }
    response = `Ödeme yapmak için aşağıdaki butonu kullanabilirsin. 💳\n\n[ÖDEME_BUTONU]`;
    session.subState = 'COMPLETE';
    break;

  case 'COMPLETE':
    response = `🎉 Tebrikler! Alışverişi başarıyla tamamladın!\n\nBulunanlar: ${foundStr}\nEksikler: ${missingStr}\n\nHarika iş çıkardın!`;
    delete sessions[sessionId];
    return [{ json: { response, needsLLM: false, llmSystemPrompt: '', llmUserPrompt: '', session, sessionId } }];

  default:
    session.subState = 'INIT';
    response = `Listendeki ürünler: ${foundStr}. Kasaya geçelim mi?`;
}

sessions[sessionId] = session;
return [{ json: { response, needsLLM, llmSystemPrompt, llmUserPrompt, session, sessionId } }];

// ============================================================
// PREPARE LLM NODE v2
// ============================================================
const { response, needsLLM, llmSystemPrompt, llmUserPrompt, session, sessionId } = $input.first().json;

// needsLLM=true ise veriyi global'a kaydet — ParseLLMResponse okuyacak
if (needsLLM) {
  const globalData = $getWorkflowStaticData('global');
  globalData['__prepare__'] = { response, needsLLM, llmSystemPrompt, llmUserPrompt, session, sessionId };
}

return [{ json: {
  response,
  needsLLM: needsLLM || false,
  llmSystemPrompt: llmSystemPrompt || '',
  llmUserPrompt: llmUserPrompt || '',
  session,
  sessionId,
  groqBody: needsLLM ? JSON.stringify({
    model: 'llama-3.3-70b-versatile',
    messages: [
      { role: 'system', content: llmSystemPrompt || '' },
      { role: 'user', content: llmUserPrompt || '' }
    ],
    max_tokens: 200,
    temperature: 0.4
  }) : ''
} }];

// ============================================================
// PARSE LLM RESPONSE NODE (Güncel)
// İki yoldan gelebilir:
// 1. needsLLM=false → CheckNeedsLLM false → direkt buraya (PrepareLLM verisi)
// 2. needsLLM=true  → GroqAPI → buraya (Groq yanıtı, ama PrepareLLM verisi yok)
//
// Çözüm: Global static data'da PrepareLLM verisini saklıyoruz
// ============================================================

const input = $input.first().json;
const globalData = $getWorkflowStaticData('global');

// Bu input GroqAPI'den mi yoksa doğrudan mı geliyor?
// GroqAPI'den gelirse "choices" alanı olur
const isGroqResponse = !!input.choices;

let prepareData, groqData;

if (isGroqResponse) {
  // Groq'tan geldi — PrepareLLM verisini global'dan al
  groqData = input;
  prepareData = globalData['__prepare__'] || {};
} else {
  // Doğrudan geldi (needsLLM=false) — PrepareLLM verisi
  prepareData = input;
  groqData = null;
  // Global'a kaydet (ileride lazım olursa diye)
  globalData['__prepare__'] = input;
}

const needsLLM = prepareData.needsLLM || false;
const sessionId = prepareData.sessionId;
let finalResponse = prepareData.response || '';
let finalSession = JSON.parse(JSON.stringify(prepareData.session || {}));

if (needsLLM && groqData) {
  try {
    if (groqData.error) throw new Error(groqData.error.message);

    const raw = (groqData.choices?.[0]?.message?.content || '').trim();
    const isJsonExpected = prepareData.llmUserPrompt !== '__TESVIK__';

    if (!isJsonExpected) {
      finalResponse = raw || 'Hadi devam edelim!';
    } else {
      let parsed = null;
      try {
        const cleaned = raw.replace(/```json|```/g, '').trim();
        parsed = JSON.parse(cleaned);
      } catch (e) {
        finalResponse = 'Tekrar söyler misin?';
        parsed = null;
      }

      if (parsed) {
        finalResponse = parsed.response || 'Devam et!';

        // State 0 WAITING_COUNT
        if (parsed.count === 2) {
          finalSession.productList = ['süt', 'yumurta'];
          finalSession.subState = 'WAITING_START';
          finalSession.timeoutCount = 0;
        } else if (parsed.count === 3) {
          finalSession.productList = ['süt', 'yumurta', 'ekmek'];
          finalSession.subState = 'WAITING_START';
          finalSession.timeoutCount = 0;
        }

        // State 0 WAITING_START
        if (parsed.ready === true) {
          finalSession.currentState = 1;
          finalSession.subState = 'INIT';
          finalSession.timeoutCount = 0;
        }

        // --- SONRADAN EKLENEN STATE VE İZLEME KONTROLLERİ ---

        // State 1, 2, 3 için ipucu sayısı takibi
        if (parsed.hintCount !== undefined && parsed.hintCount !== null) {
          finalSession.hintCount = Number(parsed.hintCount);
        }

        // State 4 (Exception Handling) ve ürün bulma/vazgeçme senaryoları
        if (parsed.itemAction) {
          finalSession.itemStatuses = finalSession.itemStatuses || {};
          const missItem = finalSession.notFoundItem || "ürün";
          finalSession.itemStatuses[missItem] = parsed.itemAction;

          // Eğer ürün bulundu ya da yerine alternatif alındıysa:
          if (parsed.itemAction === 'substituted' || parsed.itemAction === 'found') {
            finalSession.foundItems = finalSession.foundItems || [];
            if (!finalSession.foundItems.includes(missItem)) {
              finalSession.foundItems.push(missItem);
            }
          } 
          // Eğer ürün listeden çıkarıldı ya da başka markete ertelendiyse:
          else if (parsed.itemAction === 'removed' || parsed.itemAction === 'postponed') {
            finalSession.missingItems = finalSession.missingItems || [];
            if (!finalSession.missingItems.includes(missItem)) {
              finalSession.missingItems.push(missItem);
            }
          }
        }

        // State 4'te başarısız deneme sayısını tetikleyen yapı
        if (parsed.incrementAttempts) {
          finalSession.exceptionAttempts = (finalSession.exceptionAttempts || 0) + 1;
        }

        // State 4'te kullanıcının seçtiği çözüm yolunu (ör: A, B, C, D) takip etmek için
        if (parsed.choice && parsed.choice !== "unknown") {
          finalSession.currentChoice = parsed.choice;
        }

        // ---------------------------------------------------

        // Genel geçiş (tüm State'lerin ortak çalıştırdığı kısım)
        if (parsed.nextState !== undefined && parsed.nextState !== null) {
          finalSession.currentState = Number(parsed.nextState);
        }
        if (parsed.nextSubState !== undefined && parsed.nextSubState !== null) {
          finalSession.subState = String(parsed.nextSubState);
        }
      }
    }

    // Session'ı kaydet
    globalData[sessionId] = finalSession;

  } catch (err) {
    finalResponse = 'Bir sorun oluştu, tekrar dener misin?';
  }
}

// needsLLM=false ise PrepareLLM verisini global'a kaydet (sonraki adım için)
if (!needsLLM && sessionId) {
  globalData['__prepare__'] = prepareData;
}

return [{ json: {
  response: finalResponse,
  currentState: finalSession?.currentState ?? 0,
  subState: finalSession?.subState ?? 'INIT',
  source: needsLLM ? 'llm' : 'rule',
  sessionId,
  timestamp: new Date().toISOString()
} }];
